// Categories that ship an '<category>_any' hero sprite, used as a graceful fallback
// when a specific imageKey has no dedicated sprite.
const FALLBACK_KEY = 'nigiri_any';

/**
 * Resolve the pixel sprite for a menu item. Tries the exact imageKey, then the
 * category's '_any' hero sprite, then a neutral default — so every item resolves.
 */
export function getItemSprite(
  imageKey: string | undefined,
  category: string | undefined,
): ImageSourcePropType {
  if (imageKey && SPRITE_BY_KEY[imageKey]) return SPRITE_BY_KEY[imageKey]!;
  if (category) {
    const anyKey = `${category}_any`;
    if (SPRITE_BY_KEY[anyKey]) return SPRITE_BY_KEY[anyKey]!;
  }
  return SPRITE_BY_KEY[FALLBACK_KEY]!;
}

export function hasItemSprite(imageKey: string | undefined): boolean {
  return !!(imageKey && SPRITE_BY_KEY[imageKey]);
}
